),

activity AS (
  SELECT
    t.user_id,
    t.tier,
    u.last_match_finished_at,
    DATE_DIFF(CURRENT_DATE(), DATE(u.last_match_finished_at), DAY) AS days_since_last_match
  FROM tier_users t
  LEFT JOIN  u
    ON t.user_id = u.user_id
)

SELECT
  tier,
  COUNT(*) AS total_users,
  COUNTIF(last_match_finished_at IS NOT NULL) AS found_in_datamart,
  COUNTIF(days_since_last_match <= 7) AS match_7d,
  COUNTIF(days_since_last_match <= 14) AS match_14d,
  COUNTIF(days_since_last_match <= 30) AS match_30d,
  COUNTIF(days_since_last_match <= 90) AS match_90d,
  COUNTIF(days_since_last_match > 90) AS dormant_90d_plus,
  COUNTIF(last_match_finished_at IS NULL) AS never_matched,
  
  -- Percentages
  ROUND(100.0 * COUNTIF(days_since_last_match <= 7) / COUNT(*), 1) AS pct_7d,
  ROUND(100.0 * COUNTIF(days_since_last_match <= 30) / COUNT(*), 1) AS pct_30d,
  ROUND(100.0 * COUNTIF(days_since_last_match <= 90) / COUNT(*), 1) AS pct_90d
  
FROM activity
GROUP BY tier
ORDER BY 
  CASE tier 
    WHEN 'entry_5_only' THEN 1 
    WHEN 'c2_250' THEN 2 
    WHEN 'whale_1000' THEN 3 
  END
